import json
import base64
import hmac
import hashlib
from typing import Dict, Any, Optional

def decode_jwt(token: str, secret: Optional[str] = None, verify: bool = False) -> Dict[str, Any]:
    """
    Decode and optionally verify a JWT token for debugging purposes.
    
    Args:
        token (str): The JWT token to decode
        secret (str, optional): Secret key for verification (required if verify=True)
        verify (bool): Whether to verify the signature
        
    Returns:
        dict: Decoded token contents including header, payload, and signature status
    """
    try:
        # Split token into parts
        parts = token.split('.')
        if len(parts) != 3:
            raise ValueError("Invalid JWT token format")
        
        header_b64, payload_b64, signature_b64 = parts
        
        # Decode header
        header_bytes = base64.urlsafe_b64decode(header_b64 + '=' * (4 - len(header_b64) % 4))
        header = json.loads(header_bytes)
        
        # Decode payload
        payload_bytes = base64.urlsafe_b64decode(payload_b64 + '=' * (4 - len(payload_b64) % 4))
        payload = json.loads(payload_bytes)
        
        # Verify signature if requested
        signature_verified = True
        if verify and secret:
            # Create expected signature
            message = f"{header_b64}.{payload_b64}"
            expected_signature = base64.urlsafe_b64encode(
                hmac.new(secret.encode(), message.encode(), hashlib.sha256).digest()
            ).decode().rstrip('=')
            
            # Compare signatures
            signature_verified = hmac.compare_digest(signature_b64, expected_signature)
        
        return {
            "header": header,
            "payload": payload,
            "signature_verified": signature_verified,
            "raw": {
                "header": header_b64,
                "payload": payload_b64,
                "signature": signature_b64
            }
        }
        
    except Exception as e:
        return {"error": str(e)}

